// Index ALL Missive labels with category/sub_category classification
// Match recipient client labels to CRM companies
//
// Categories:
//   Action       — labels 0-6 + Written by Abel
//   Recipients   — under A - Recipients (sub: Current Clients, Prospects, etc.)
//   REF          — reference/archive labels
//   Other        — anything else

const response = $('Fetch Missive Labels').first().json;
const allLabels = response.shared_labels || [];
const clients = $('Get All Clients').all();

// Identify leaf nodes (no other label has this one as parent)
const parentIds = new Set(allLabels.map(l => l.parent).filter(Boolean));

// Build CRM client lookup
const clientMap = {};
for (const c of clients) {
  const name = (c.json.company_name || '').toLowerCase().trim();
  if (name) clientMap[name] = c.json.clickup_id;
}

// Categorize each label
function categorize(label) {
  const path = label.name_with_parent_names || label.name;
  const parts = path.split('/');
  const top = parts[0];

  // Action labels: 0-6 prefix or "Written by Abel"
  if (/^[0-6]\s*-/.test(top) || top === 'Written by Abel') {
    // Sub-category is the top-level label name (groups children with parent)
    return { category: 'Action', sub_category: top };
  }

  // Recipients: under A - Recipients
  if (top === 'A - Recipients') {
    if (parts.length >= 2) {
      // Clean sub-category: "A - Current Clients" → "Current Clients"
      const rawSub = parts[1];
      const cleanSub = rawSub.replace(/^[A-H]\s*-\s*/, '').trim();
      return { category: 'Recipients', sub_category: cleanSub };
    }
    return { category: 'Recipients', sub_category: '' };
  }

  // REF labels
  if (top === 'REF') {
    if (parts.length >= 2) {
      return { category: 'REF', sub_category: parts[1] };
    }
    return { category: 'REF', sub_category: '' };
  }

  return { category: 'Other', sub_category: '' };
}

// Sub-categories eligible for CRM matching
const crmMatchCategories = ['Current Clients', 'Prospects', 'Former clients', '3CV'];

// Process all labels
const labelRows = [];
const clientUpdates = [];

for (const l of allLabels) {
  const { category, sub_category } = categorize(l);
  const path = l.name_with_parent_names || l.name;
  const isLeaf = !parentIds.has(l.id);

  // CRM matching: only for recipient leaf labels in client-relevant sub-categories
  let matchedClickupId = '';
  if (category === 'Recipients' && isLeaf && crmMatchCategories.includes(sub_category)) {
    // Extract company name: "FX - Fox" → "Fox"
    const nameParts = l.name.split(' - ');
    const extractedName = nameParts.length >= 2
      ? nameParts.slice(1).join(' - ').trim()
      : l.name.trim();
    const extractedLower = extractedName.toLowerCase();

    // Exact match first
    matchedClickupId = clientMap[extractedLower] || '';

    // Substring match fallback
    if (!matchedClickupId) {
      for (const [clientName, clickupId] of Object.entries(clientMap)) {
        if (clientName.includes(extractedLower) || extractedLower.includes(clientName)) {
          matchedClickupId = clickupId;
          break;
        }
      }
    }
  }

  // All labels go to the Missive Labels table
  labelRows.push({
    label_id: l.id,
    label_name: l.name,
    category: category,
    sub_category: sub_category,
    parent_path: path,
    is_leaf: isLeaf ? 'true' : 'false',
    matched_cu_crm_id: matchedClickupId,
    _outputType: 'label'
  });

  // Matched client labels also update Clickup Clients
  if (matchedClickupId) {
    clientUpdates.push({
      clickup_id: matchedClickupId,
      missive_label_id: l.id,
      _outputType: 'client'
    });
  }
}

const combined = [...labelRows, ...clientUpdates];
if (combined.length === 0) return [];
return combined;
